public class UppercaseSecondChar {

    public static void main(String[] args) {

        String input = "My name is Praveen";
        String[] words = input.split(" ");

        StringBuilder result = new StringBuilder();

        for (String word : words) {
            if (word.length() >= 2) {
                // Convert 2nd character to uppercase
                char secondChar = Character.toUpperCase(word.charAt(1));
                result.append(word.charAt(0))
                      .append(secondChar)
                      .append(word.substring(2));
            } else {
                // If word has only one character
                result.append(word);
            }
            result.append(" ");
        }

        System.out.println(result.toString().trim());
    }
}
